import { useEffect, useMemo, useState, useRef, useCallback } from 'react'
import { LanguageEnum } from '@common/constants/language'
import { getLanguage } from '@common/utils/localStorage'
import { isReadServerTextData } from '@common/constants/env'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { useTranslation } from 'react-i18next'
import AddProjectUpload from '@common/components/AddProjectUpload'
import { Button, Select, Link } from '@arco-design/web-react'
import UnifiedTableStyle from '@common/components/UnifiedTableStyle'
import { renderEllipsisText } from '@common/components/EllipsisText'
import {
  measurementCycleEnum,
  measurementMechanismEnum,
  measurementTypeEnum,
  assemblyMethodEnum,
  formulasEnum,
  measurementUnitEnum,
  kpiTypeEnum,
} from '@/constants/strategicKpis.ts'
import { IconEdit, IconDelete } from '@arco-design/web-react/icon'
import './index.less'
import { useNavigate, useParams, useLocation } from 'react-router-dom'
import { kpiGenerateAi, kpiRegenerateAi } from '@/service'
import { underline } from '@/utils/tools'
import { useRequest } from 'ahooks'
import EditDetailModal from '@/pages/StrategicKpis/KpisManagement/Ai/components/KpiActivitySetting/components/RegenerateModal'
import _ from 'lodash'
import ExcelJS from 'exceljs'

const BulkKpiGeneration = () => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'project', 'activities', 'kpis'])
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const location = useLocation()
  const {
    objectiveId,
    orgId,
    type,
    kpiType,
    generationType,
    cycleName,
    objectiveName,
    responsiblePersonEmails,
    departmentName,
    typeLabel,
  } = location.state || {}

  const [fileList, setFileList] = useState<any>([])
  const [allUserIntent, setAllUserIntent] = useState<any>()
  const tableRef = useRef(null)
  const [tableData, setTableData] = useState<any>([])
  const [record, setRecord] = useState<any>()
  const [editDetailModalVisible, setEditDetailModalVisible] = useState(false)
  const navigate = useNavigate()

  const measurementMechanismOptions = [
    {
      label: t('kpis:informationTypes.withFormula'),
      value: measurementMechanismEnum['with formula'],
    },
    {
      label: t('kpis:informationTypes.withoutFormula'),
      value: measurementMechanismEnum['without formula'],
    },
  ]
  const measurementTypeOptions = [
    {
      label: t('kpis:informationTypes.increasingBetter'),
      value: measurementTypeEnum['Increasing Better'],
    },
    {
      label: t('kpis:informationTypes.decreasingBetter'),
      value: measurementTypeEnum['Decreasing Better'],
    },
  ]

  const rawOptions = [
    {
      label: t('kpis:informationTypes.sum'),
      value: assemblyMethodEnum.Sum,
      visible: true,
    },
    {
      label: t('kpis:informationTypes.average'),
      value: assemblyMethodEnum.Average,
      visible: true, // 控制是否显示
    },
    {
      label: t('kpis:informationTypes.lastValue'),
      value: assemblyMethodEnum.LastValue,
      visible: true,
    },
  ]
  const assemblyMethodOptions = rawOptions.filter((item) => item.visible)

  const measurementCycleOptionsData = useMemo(() => {
    const baseOptions = [
      {
        label: t('kpis:informationTypes.annual'),
        value: measurementCycleEnum.Annual,
      },
      {
        label: t('kpis:informationTypes.semiannual'),
        value: measurementCycleEnum.Semiannual,
      },
      {
        label: t('kpis:informationTypes.quarter'),
        value: measurementCycleEnum.Quarter,
      },
    ]

    if (
      kpiType === kpiTypeEnum.operationalKpi ||
      kpiType === kpiTypeEnum.processKpi
    ) {
      return [
        ...baseOptions,
        { label: t('milestones:monthly'), value: measurementCycleEnum.Monthly },
      ]
    }
    return baseOptions
  }, [t, kpiType])
  const formulasOptions = [
    {
      label: t('formula:formulaDataTitle.growthRate'),
      value: formulasEnum.GrowthRate,
    },
    {
      label: t('formula:formulaDataTitle.division'),
      value: formulasEnum.Division,
    },
    {
      label: t('formula:formulaDataTitle.sum'),
      value: formulasEnum.Sum,
    },
    {
      label: t('formula:formulaDataTitle.average'),
      value: formulasEnum.Average,
    },
    {
      label: t('project:projectDeleteInfo.duration'),
      value: formulasEnum.Duration,
    },
  ]

  const measurementUnitOptions = [
    {
      label: t('kpis:informationTypes.percentage'),
      value: measurementUnitEnum.Percentage,
    },
    {
      label: t('kpis:informationTypes.currency'),
      value: measurementUnitEnum.Currency,
    },
    {
      label: t('kpis:informationTypes.number'),
      value: measurementUnitEnum.Number,
    },
    {
      label: t('kpis:informationTypes.hour'),
      value: measurementUnitEnum.Hour,
    },
    {
      label: t('kpis:informationTypes.day'),
      value: measurementUnitEnum.Day,
    },
  ]
  const columns = [
    {
      title: t('kpis:list.column.name'),
      dataIndex: 'kpiName',
      key: 'kpiName',
      width: 200,
      render: (_, record) => {
        const kpiName = isLanguageAR ? record.kpiNameAr : record.kpiName
        return (
          <div
            onClick={() => {
              setRecord([record])
              setEditDetailModalVisible(true)
            }}
          >
            {renderEllipsisText(kpiName, underline())}
          </div>
        )
      },
    },
    {
      title: t('kpis:add.information.mechanism'),
      dataIndex: 'measurementMechanism',
      key: 'measurementMechanism',
      width: 200,
      render: (_, record) => {
        return (
          <div>
            <Select
              value={record.measurementMechanism}
              options={measurementMechanismOptions}
              placeholder={t('login:information.common.pleaseSelect')}
              onChange={(val) =>
                handleColumnsChange(
                  record.id,
                  'measurementMechanism',
                  tableData,
                  val,
                )
              }
            />
          </div>
        )
      },
    },
    {
      title: t('kpis:add.information.type'),
      dataIndex: 'measurementType',
      key: 'measurementType',
      width: 200,
      render: (_, record) => {
        return (
          <div>
            <Select
              value={record.measurementType}
              // disabled={disableMeasurementType}
              options={measurementTypeOptions}
              placeholder={t('login:information.common.pleaseSelect')}
              onChange={(val) =>
                handleColumnsChange(
                  record.id,
                  'measurementType',
                  tableData,
                  val,
                )
              }
            />
          </div>
        )
      },
    },
    {
      title: t('kpis:add.information.method'),
      dataIndex: 'assemblyMethod',
      key: 'assemblyMethod',
      width: 200,
      render: (_, record) => {
        return (
          <div>
            <Select
              value={record.assemblyMethod}
              // disabled={disableAssemblyMethod}
              options={assemblyMethodOptions}
              placeholder={t('login:information.common.pleaseSelect')}
              onChange={(val) =>
                handleColumnsChange(record.id, 'assemblyMethod', tableData, val)
              }
            />
          </div>
        )
      },
    },
    {
      title: t('kpis:add.information.cycle'),
      dataIndex: 'measurementCycle',
      key: 'measurementCycle',
      width: 200,
      render: (_, record) => {
        return (
          <div>
            <Select
              value={record.measurementCycle}
              // disabled={!(formStartDate && formEndDate)}
              placeholder={t('login:information.common.pleaseSelect')}
              options={measurementCycleOptionsData}
              onChange={(val) =>
                handleColumnsChange(
                  record.id,
                  'measurementCycle',
                  tableData,
                  val,
                )
              }
            />
          </div>
        )
      },
    },
    {
      title: t('kpis:add.information.formulas'),
      dataIndex: 'formulas',
      key: 'formulas',
      width: 200,
      render: (_, record) => {
        return (
          <div>
            <Select
              value={record.formulas}
              options={formulasOptions}
              placeholder={t('login:information.common.pleaseSelect')}
              // disabled={
              //   formMechanism != measurementMechanismEnum['with formula']
              // }
              onChange={(val) =>
                handleColumnsChange(record.id, 'formulas', tableData, val)
              }
            />
          </div>
        )
      },
    },
    {
      title: t('kpis:add.information.unit'),
      dataIndex: 'measurementUnit',
      key: 'measurementUnit',
      width: 200,
      render: (_, record) => {
        return (
          <div>
            <Select
              placeholder={t('login:information.common.pleaseSelect')}
              options={measurementUnitOptions}
              value={record.measurementUnit}
              onChange={(val) =>
                handleColumnsChange(
                  record.id,
                  'measurementUnit',
                  tableData,
                  val,
                )
              }
            />
          </div>
        )
      },
    },
    {
      title: t('common:columns.action'),
      dataIndex: 'action',
      key: 'action',
      // fixed: 'right',
      width: 150,
      render: (_, record) => {
        return (
          <div>
            <Link
              icon={<IconEdit />}
              onClick={() => {
                setRecord([record])
                setEditDetailModalVisible(true)
              }}
            >
              {t('common:btn.edit')}
            </Link>
            <Link
              icon={<IconDelete />}
              style={{ color: '#F5626C' }}
              className='coc-table-link'
              onClick={() => handleDelete(record.id)}
            >
              {t('common:btn.delete')}
            </Link>
          </div>
        )
      },
    },
  ]
  useEffect(() => {
    // 只在用户保存 modal 时（isModal: true）才回写 tableData，避免仅打开 modal 时触发不必要的刷新
    if (record?.[0]?.isModal) {
      setTableData((prev) => {
        if (!Array.isArray(prev)) return prev
        return prev.map((item, index) => {
          const currentId = index + 1
          if (currentId !== record?.[0]?.id) return item
          const { isModal, id, ...rest } = record?.[0]
          return rest
        })
      })
    }
  }, [record])

  // 删除
  const handleDelete = (id) => {
    setTableData((prev) => {
      if (!Array.isArray(prev)) return prev
      return prev.filter((item, index) => index + 1 !== id)
    })
  }

  ///监听数据变化
  const handleColumnsChange = (id, key, data, value) => {
    setTableData((prev) => {
      if (!Array.isArray(prev)) return prev
      return prev.map((item, index) => {
        const currentId = index + 1
        if (currentId !== id) return item
        const newMechanism =
          key === 'measurementMechanism' ? value : item?.measurementMechanism
        return {
          ...item,
          formulas:
            newMechanism == measurementMechanismEnum['without formula']
              ? undefined
              : item?.formulas,
          [key]: value,
        }
      })
    })
  }
  // 首次生成数据
  const { run: runKpiGenerateAi, loading: kpiGenerateAiLoading } = useRequest(
    kpiGenerateAi,
    {
      manual: true,
      onSuccess: (res: any) => {
        const data = res?.map((item) => {
          return {
            ...item,
            formulas:
              item?.measurementMechanism ==
              measurementMechanismEnum['without formula']
                ? undefined
                : item?.formulas,
          }
        })
        setTableData((prev) =>
          Array.isArray(prev) && prev.length > 0 ? [...prev, ...data] : data,
        )
      },
    },
  )
  //再次生成ai数据
  const { run: runKpiRegenerateAi, loading: kpiRegenerateAiLoading } =
    useRequest(kpiRegenerateAi, {
      manual: true,
      onSuccess: (res: any) => {
        const data = res?.map((item) => {
          return {
            ...item,
            formulas:
              item?.measurementMechanism ==
              measurementMechanismEnum['without formula']
                ? undefined
                : item?.formulas,
          }
        })
        if (tableData?.length > 0) {
          setTableData((prev) => [...prev, ...data])
        } else {
          setTableData(data)
        }
      },
    })

  //发送文件进行生成
  const handelFileListSend = () => {
    const aiUploadData = {
      userIntent: allUserIntent,
      objectiveId: objectiveId,
      orgId: orgId,
      kpiType: kpiType,
      generationType: generationType,
      attachmentList: fileList,
      historyList: tableData,
    }
    if (tableData?.length > 0) {
      runKpiRegenerateAi(aiUploadData)
    } else {
      runKpiGenerateAi(aiUploadData)
    }
  }

  //获取表格数据
  const getList = useCallback(() => {
    // if (selectCycleId === 'id') {
    const data = tableData?.map((item, index) => {
      return {
        ...item,
        id: index + 1,
      }
    })
    return Promise.resolve({ list: data, total: 0 })
    // }
  }, [tableData])

  // 导出 Excel（按模板）
  const handelExportXlsx = async () => {
    if (!Array.isArray(tableData) || tableData.length === 0) return

    const monthlyData = tableData.filter(
      (item) => item.measurementCycle === measurementCycleEnum.Monthly,
    )
    const otherData = tableData.filter(
      (item) => item.measurementCycle !== measurementCycleEnum.Monthly,
    )

    const getLabelByValue = (
      options: { label: string; value: any }[],
      value: any,
    ): string => options.find((o) => o.value === value)?.label ?? ''

    const kpiTypeOptions = [
      { label: t('kpis:strategicKpi'), value: kpiTypeEnum.strategicKpi },
      { label: t('kpis:operationalKpi'), value: kpiTypeEnum.operationalKpi },
      { label: t('kpis:processKpi'), value: kpiTypeEnum.processKpi },
      { label: t('kpis:enablerKpi'), value: kpiTypeEnum.enablerKpi },
    ]

    const exportGroup = async (
      data: any[],
      templateUrl: string,
      fileName: string,
      isMonthly: boolean,
    ) => {
      const res = await fetch(templateUrl)
      const arrayBuffer = await res.arrayBuffer()

      const workbook = new ExcelJS.Workbook()
      await workbook.xlsx.load(arrayBuffer)
      const worksheet = workbook.getWorksheet('Sheet2') as any

      data.forEach((item, rowIdx) => {
        const rowNum = rowIdx + 3 // 数据从第3行开始（第2行为表头），直接覆写模板示例行
        const cycleData: any[] = item.measurementCycleData || []
        const row = worksheet.getRow(rowNum)
        console.log('123123', Array.isArray(responsiblePersonEmails)
          ? responsiblePersonEmails.join(',') || null
          : responsiblePersonEmails || null)
        row.getCell('A').value = cycleName || null
        row.getCell('B').value = objectiveName || null
        row.getCell('C').value = Array.isArray(responsiblePersonEmails)
          ? responsiblePersonEmails.join(',') || null
          : responsiblePersonEmails || null
        row.getCell('D').value = departmentName || null
        row.getCell('E').value = item.kpiName || null
        row.getCell('F').value = item.kpiNameAr || null
        row.getCell('G').value = item.description || null
        row.getCell('H').value = item.descriptionAr || null
        row.getCell('I').value = item.measurementFormulasDesc || null
        row.getCell('J').value = item.measurementFormulasDescAr || null
        row.getCell('K').value = item.startDate || null
        row.getCell('L').value = item.endDate || null
        row.getCell('M').value =
          getLabelByValue(kpiTypeOptions, kpiType) || null
        row.getCell('N').value = typeLabel || null
        row.getCell('O').value =
          getLabelByValue(measurementCycleOptionsData, item.measurementCycle) ||
          null
        row.getCell('P').value =
          getLabelByValue(measurementTypeOptions, item.measurementType) || null
        row.getCell('Q').value =
          getLabelByValue(
            measurementMechanismOptions,
            item.measurementMechanism,
          ) || null
        row.getCell('R').value =
          getLabelByValue(assemblyMethodOptions, item.assemblyMethod) || null
        row.getCell('S').value =
          getLabelByValue(measurementUnitOptions, item.measurementUnit) || null
        row.getCell('T').value =
          getLabelByValue(formulasOptions, item.formulas) || null

        // 目标值列：月度12列（U-AF，sort 1-12），季度4列（U-X，sort 1-4）
        // Annual 只有一个周期（Q4），其 sort=1 但应写入 Q4 位置（列 X）
        // Semiannual：H1→Q2（列 V），H2→Q4（列 X）
        if (item.measurementCycle === measurementCycleEnum.Annual) {
          row.getCell('X').value = cycleData[0]?.targetPerformance ?? null
        } else if (item.measurementCycle === measurementCycleEnum.Semiannual) {
          const semiannualColMap: Record<string, string> = { H1: 'V', H2: 'X' }
          cycleData.forEach((d) => {
            const col = semiannualColMap[d.code]
            if (col) row.getCell(col).value = d.targetPerformance ?? null
          })
        } else {
          const targetCols = isMonthly
            ? ['U', 'V', 'W', 'X', 'Y', 'Z', 'AA', 'AB', 'AC', 'AD', 'AE', 'AF']
            : ['U', 'V', 'W', 'X']
          targetCols.forEach((col, i) => {
            const periodData = cycleData.find((d) => d.sort === i + 1)
            row.getCell(col).value = periodData?.targetPerformance ?? null
          })
        }

        row.commit()
      })

      // 删除模板中超出实际数据行数的多余空行
      const firstExtraRow = data.length + 3
      const totalRows = worksheet.rowCount
      if (totalRows >= firstExtraRow) {
        worksheet.spliceRows(firstExtraRow, totalRows - firstExtraRow + 1)
      }

      // ExcelJS 解析模板时把范围（如 M3:M1000）展开为每个单元格地址（M3, M4...M1000）分别存入 model
      // 只需删掉数据行范围之外的地址，写入时 optimiseDataValidations 会自动合并回范围
      const dvModel: Record<string, any> =
        worksheet.dataValidations?.model ?? {}
      const lastDataRow = data.length + 2
      Object.keys(dvModel).forEach((addr) => {
        const m = addr.replace(/\$/g, '').match(/^[A-Z]+(\d+)$/)
        if (m) {
          const rowNum = parseInt(m[1], 10)
          if (rowNum < 3 || rowNum > lastDataRow) {
            delete dvModel[addr]
          }
        }
      })

      const buffer = await workbook.xlsx.writeBuffer()
      const blob = new Blob([buffer], {
        type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      })
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = fileName
      a.click()
      URL.revokeObjectURL(url)
    }

    if (monthlyData.length > 0) {
      await exportGroup(
        monthlyData,
        '/KPI-Monthly-template.xlsx',
        'KPI-Monthly.xlsx',
        true,
      )
    }
    if (otherData.length > 0) {
      await exportGroup(
        otherData,
        '/KPI-Quarterly-template.xlsx',
        'KPI-Quarterly.xlsx',
        false,
      )
    }
  }
  return (
    <div className='bulkKpiGeneration'>
      <div className='bulkKpiGeneration-upload'>
        <AddProjectUpload
          fileList={fileList}
