  Form,
  Select,
  Grid,
  Radio,
  Button,
  TreeSelect,
} from '@arco-design/web-react'
import { isReadServerTextData } from '@common/constants/env'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { useTranslation } from 'react-i18next'
import { useNavigate } from 'react-router-dom'
import {
  GenerationType,
  kpiTypeEnum,
  strategyApiTypeEnum,
} from '@/constants/strategicKpis'
import { useState, useEffect } from 'react'
import { useGetState, useRequest } from 'ahooks'
import { getUserList, getOrgTreeRecursion } from '@/service'
import { getMailString, transformData } from '@/utils/tools.ts'
import { getLanguage } from '@common/utils/localStorage.ts'
import { LanguageEnum } from '@common/constants/language.ts'
import SelectTree from '@common/components/SelectTree'
import { getCyclePillarObjectiveRequest } from '@/service/apis/kpis.ts'
import dayjs from 'dayjs'
import { converTimeFormat } from '@/utils/processActivitiesTime.ts'
import { StrategyCycleStatusEnum } from '@/constants/cycle'

const FormItem = Form.Item
const Row = Grid.Row
const Col = Grid.Col
const RadioGroup = Radio.Group

const KpiInfo = () => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['common', 'project', 'activities'])
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const [form] = Form.useForm()

  const generationType = Form.useWatch('generationType', form)
  const objective = Form.useWatch('objective', form)

  const [departmentData, setDepartmentData] = useState<any>([])
  const [userList, setUserList] = useState([])
  const [rawUserData, setRawUserData] = useState<any[]>([])

  // Cycle / Pillar / Objective tree
  const [allObjectiveOption, setAllObjectiveOption] = useState([])
  const [objectiveDefaultExpandedKeys, setObjectiveDefaultExpandedKeys] =
    useState([])
  const [allCycleInfo, setAllCycleInfo] = useState([])
  const [allPillarInfo, setAllPillarInfo] = useState([])
  const [selectedCycleId, setSelectedCycleId] = useState<any>(null)
  const [selectedPillarId, setSelectedPillarId] = useState<any>(null)
  const [currentCycleDateRange, setCurrentCycleDateRange] = useGetState({
    startDate: '',
    endDate: '',
  })
  const [cyclePillarObjectiveTreeData, setCyclePillarObjectiveTreeData] =
    useGetState([])

  const navigate = useNavigate()

  const TYPE_DESC = {
    0: t('project:projectType.strategic'),
    1: t('project:projectType.operational'),
  }
  /** 文案暂用英文硬编码，不接 i18n / 翻译统计；后续再接 kpis 词条 */
  const L = {
    title: t('project:ai.infoTitle'),
    strategyObjective: t('project:projectInfo.projectStrategyObjective'),
    responsiblePerson: t('kpis:list.column.responsiblePerson'),
    department: t('historyLog:columns.department'),
    kpiType: t('kpis:kpiType'),
    batchCreation: t('kpis:batchCreationKpis'),
    batchSingle: t('kpis:singleKpi'),
    batchBulk: t('kpis:bulkKpiGeneration'),
    wizardSetup: t('kpis:wizardSetup'),
    wizardStrategicTitle: t('dashboard:strategicKPI'),
    wizardStrategicDesc: t('kpis:organization'),
    wizardProcessTitle: t('kpis:processKpi'),
    wizardProcessDesc: t('kpis:operational'),
    pleaseSelect: t('common:pleaseSelect'),
    wizardOperationalTitle: t('kpis:operationalKpi'),
    wizardOperationalDesc: t('tracksDayToDay'),
    wizardEnablerTitle: t('kpis:enablerKpi'),
    wizardEnablerDesc: t('kpis:assesses'),
  } as const

  const wizardSetupOption = [
    {
      value: kpiTypeEnum.strategicKpi,
      label: L.wizardStrategicTitle,
      desc: L.wizardStrategicDesc,
    },
    {
      value: kpiTypeEnum.operationalKpi,
      label: L.wizardOperationalTitle,
      desc: L.wizardOperationalDesc,
    },
    {
      value: kpiTypeEnum.processKpi,
      label: L.wizardProcessTitle,
      desc: L.wizardProcessDesc,
    },
    {
      value: kpiTypeEnum.enablerKpi,
      label: L.wizardEnablerTitle,
      desc: L.wizardEnablerDesc,
    },
  ]

  const strategyApiTypeOptions = [
    {
      label: t('kpis:informationTypes.inStats'),
      value: strategyApiTypeEnum['Counted in Stats'],
    },
    {
      label: t('kpis:informationTypes.exStats'),
      value: strategyApiTypeEnum['Excluded from Stats'],
    },
  ]

  // 获取 Cycle / Pillar / Objective 树形数据
  const cyclePillarObjectiveData = () => {
    getCyclePillarObjectiveRequest().then((res: any) => {
      const tempObjectiveOptionsList = []
      const tempCycleInfoList = []
      const tempPillarInfoList = []
      const tempTreeDate = res?.map((item) => {
        tempCycleInfoList.push({
          id: item.cycleId,
          cycleName: item.cycleName,
          cycleNameAr: item.cycleNameAr,
          startDate: item.startDate,
          endDate: item.endDate,
        })
        return {
          title: isLanguageAR ? item.cycleNameAr : item.cycleName,
          value: item.cycleId,
          key: item.cycleId,
          disabled: true,
          children: item.cyclePillarList?.map((pillarItem) => {
            tempPillarInfoList.push({
              id: pillarItem.pillarId,
              objectives: pillarItem.objectivesNameSerList?.map(
                (theObj) => theObj.objectiveId,
              ),
            })
            return {
              title: isLanguageAR
                ? pillarItem.pillarNameAr
                : pillarItem.pillarName,
              value: pillarItem.pillarId,
              key: pillarItem.pillarId,
              disabled: true,
              children: pillarItem.objectivesNameSerList?.map(
                (objectiveItem) => {
                  tempObjectiveOptionsList.push({
                    label: `${
                      isLanguageAR
                        ? objectiveItem.objectiveNameAr
                        : objectiveItem.objectiveName
                    }  (${TYPE_DESC[objectiveItem.type]})`,
                    value: objectiveItem.objectiveId,
                    name: objectiveItem.objectiveName,
                    nameAr: objectiveItem.objectiveNameAr,
                  })
                  return {
                    title: `${
                      isLanguageAR
                        ? objectiveItem.objectiveNameAr
                        : objectiveItem.objectiveName
                    }  (${TYPE_DESC[objectiveItem.type]})`,
                    value: objectiveItem.objectiveId,
                    key: objectiveItem.objectiveId,
                    disabled:
                      objectiveItem.cycleStatus ===
                      StrategyCycleStatusEnum.SUSPENDED,
                  }
                },
              ),
            }
          }),
        }
      })

      if (tempTreeDate?.length) {
        setCyclePillarObjectiveTreeData(tempTreeDate)
        setAllCycleInfo(tempCycleInfoList)
        setAllPillarInfo(tempPillarInfoList)
      }
      if (tempObjectiveOptionsList.length) {
        setAllObjectiveOption(tempObjectiveOptionsList)
      }
      if (tempTreeDate?.length && tempTreeDate[0].children?.length) {
        const tempExpanded = tempTreeDate[0].children.map((item) => item.value)
        setObjectiveDefaultExpandedKeys(tempExpanded)
      }
    })
  }

  // 选择 Objective 时：找到对应的 cycleId / pillarId，并计算 startDate / endDate
  const getCycleId = (objectID, cycleId) => {
    const cycleSelect = allCycleInfo.find((d) => d.id === cycleId)
    if (!cycleSelect) return

    const pillarSelect = allPillarInfo.find((item) =>
      item.objectives?.includes(objectID),
    )

    if (cycleId && pillarSelect && objectID) {
      setObjectiveDefaultExpandedKeys([cycleId, pillarSelect.id, objectID])
    }

    setSelectedCycleId(cycleId)
    setSelectedPillarId(pillarSelect?.id ?? null)
    setCurrentCycleDateRange({
      startDate: cycleSelect.startDate,
      endDate: cycleSelect.endDate,
    })

    // 计算展示用的开始/结束日期（与 KpiForm 逻辑一致）
    const currentDate = dayjs()
    const cycleStartTs = dayjs(
      converTimeFormat(cycleSelect.startDate),
    ).valueOf()
    const cycleEndTs = dayjs(converTimeFormat(cycleSelect.endDate)).valueOf()
    const isCurrentDateInCycle =
      currentDate.valueOf() >= cycleStartTs &&
      currentDate.valueOf() <= cycleEndTs

    let targetStartDate = cycleSelect.startDate
    if (isCurrentDateInCycle) {
      targetStartDate = `01/01/${currentDate.year()}`
    }

    const startDateSplitYear = targetStartDate.split('/')[2]
    const endDateTime = dayjs(converTimeFormat(targetStartDate)).isSame(
      dayjs(`${startDateSplitYear}-12-31`),
    )
      ? dayjs(converTimeFormat(targetStartDate)).format('YYYY-MM-DD')
      : dayjs(converTimeFormat(targetStartDate))
          .add(1, 'day')
          .format('YYYY-MM-DD')

    form.setFieldValue('startDate', dayjs(targetStartDate, 'DD/MM/YYYY'))
    form.setFieldValue('endDate', dayjs(endDateTime, 'YYYY-MM-DD'))
    form.setFieldValue('objective', objectID)
  }

  //获取 department 列表
  const { run: getOrgTree } = useRequest(getOrgTreeRecursion, {
    manual: true,
    onSuccess(res: any) {
      const data = transformData(res, t, true)
      setDepartmentData(data || [])
    },
    onError(e, params) {
      console.log({ e, params })
    },
  })

  // 查询用户列表
  const { run: getAllUserList, loading: userLoading } = useRequest(
    getUserList,
    {
      manual: true,
      onSuccess(data: any) {
        const userOptions = data.map((item) => ({
          label: isLanguageAR
            ? `${item.fullNameAr}(${getMailString(item.mail)})`
            : `${item.fullName}(${getMailString(item.mail)})`,
          value: item.userId,
          extra: item?.orgInfoList,
        }))
        setUserList(userOptions || [])
        setRawUserData(data || [])
      },
      onError(e, params) {
        console.log({ e, params })
      },
    },
  )

  useEffect(() => {
    getOrgTree({ cycleId: '' })
    getAllUserList({ pageNum: 1, pageSize: 10000 })
    cyclePillarObjectiveData()
  }, [])

  const getSelectResponsiblePerson = (e) => {
    form.setFieldValue('orgId', e[0]?.extra[0]?.orgId)
  }

  const findNodeTitle = (nodes: any[], targetKey: any): string => {
    for (const node of nodes) {
      if (node.key === targetKey) return node.title ?? ''
      if (node.children?.length) {
        const found = findNodeTitle(node.children, targetKey)
        if (found) return found
      }
    }
    return ''
  }

  const handleNext = () => {
    form.validate().then((values) => {
      const startDate = form.getFieldValue('startDate')
      const endDate = form.getFieldValue('endDate')

      const cycleName =
        (allCycleInfo as any[]).find((c) => c.id === selectedCycleId)
          ?.cycleName ?? ''
      const objectiveName =
        (allObjectiveOption as any[]).find((o) => o.value === values.objective)
          ?.name ?? ''
      const responsiblePersonEmails = (values.responsiblePersonList || [])
        .map(
          (userId: any) =>
            rawUserData.find((u) => u.userId === userId)?.mail ?? '',
        )
        .filter(Boolean)
        .join('; ')
      const departmentName = findNodeTitle(departmentData, values.orgId)
      const typeLabel =
        strategyApiTypeOptions.find((o) => o.value === values.type)?.label ?? ''

      const data = {
        generationType: values.generationType,
        objectiveId: values.objective,
        cycleId: selectedCycleId,
        pillarId: selectedPillarId,
        startDate: startDate
          ? dayjs(startDate).format('YYYY-MM-DD')
          : undefined,
        endDate: endDate ? dayjs(endDate).format('YYYY-MM-DD') : undefined,
        responsiblePersonList: values.responsiblePersonList,
        orgId: values.orgId,
        type: values.type,
        kpiType: values.kpiType,
        cycleName,
        objectiveName,
        responsiblePersonEmails,
        departmentName,
        typeLabel,
      }
      navigate('/strategic-kpis/kpisManagement/addAi/2', {
        state: data,
      })
    })
  }

  return (
    <div className='kpiAi-information-box'>
      <div className='kpiAi-information'>
        <div className='information-title'>{L.title}</div>
        <Form form={form} layout='vertical' className='kpi-ai-basic-form'>
          <Row gutter={24}>
            <Col span={12}>
              <FormItem
                label={L.strategyObjective}
                field='objective'
                rules={[{ required: true, message: L.pleaseSelect }]}
              >
                <SelectTree
                  isAdminPublishedEdit={false}
                  treeData={cyclePillarObjectiveTreeData}
                  onChange={(value, extra) => {
                    getCycleId(value, extra)
                  }}
                  options={allObjectiveOption}
                  expandedAllKeys={objectiveDefaultExpandedKeys}
                  selectObjectiveId={objective}
                />
              </FormItem>
            </Col>
            <Col span={12}>
              <FormItem
                label={L.responsiblePerson}
                field='responsiblePersonList'
                rules={[{ required: true, message: L.pleaseSelect }]}
              >
                <Select
                  showSearch
                  options={userList}
                  mode='multiple'
                  maxTagCount='responsive'
                  placeholder={t('login:information.common.pleaseSelect')}
                  onChange={(v, e) => {
                    getSelectResponsiblePerson(e)
                  }}
                  getPopupContainer={(triggerNode: HTMLElement) =>
                    triggerNode.parentNode as HTMLElement
                  }
                  filterOption={(inputValue, option) =>
                    option.props.value
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0 ||
                    option.props.children
                      .toLowerCase()
                      .indexOf(inputValue.toLowerCase()) >= 0
                  }
                  notFoundContent={null}
                />
              </FormItem>
            </Col>
            <Col span={12}>
              <FormItem
                label={L.department}
                field='orgId'
                rules={[{ required: true, message: L.pleaseSelect }]}
              >
                <TreeSelect
                  showSearch={true}
                  placeholder={t('membersDepartments:columns.departmentName')}
                  allowClear={true}
                  treeData={departmentData}
                  filterTreeNode={(inputText, node) =>
                    node.props.title
                      .toLowerCase()
                      .indexOf(inputText.toLowerCase()) > -1
                  }
                />
              </FormItem>
            </Col>
            <Col span={12}>
              <FormItem
                label={L.kpiType}
                field='type'
                rules={[{ required: true, message: L.pleaseSelect }]}
              >
                <Select
                  options={strategyApiTypeOptions}
                  placeholder={t('login:information.common.pleaseSelect')}
                  getPopupContainer={(triggerNode: HTMLElement) =>
                    triggerNode.parentNode as HTMLElement
                  }
                />
              </FormItem>
            </Col>

            <Col span={24}>
              <FormItem
                label={L.batchCreation}
                field='generationType'
                rules={[{ required: true, message: L.pleaseSelect }]}
              >
                <RadioGroup className='kpi-ai-batch-radio-group'>
                  <Radio value={GenerationType.Single}>{L.batchSingle}</Radio>
                  <Radio value={GenerationType.Multi}>{L.batchBulk}</Radio>
                </RadioGroup>
              </FormItem>
            </Col>

            {generationType && (
              <Col span={24}>
                <FormItem
                  label={L.wizardSetup}
                  field='kpiType'
                  rules={[{ required: true, message: L.pleaseSelect }]}
                >
                  <RadioGroup className='kpi-ai-wizard-radio-group'>
                    {wizardSetupOption.map((item) => {
                      if (generationType == GenerationType.Single) {
                        return (
                          <Radio
                            key={item.value}
                            value={item.value}
                            className='kpi-ai-wizard-radio'
                          >
                            <div className='kpi-ai-wizard-card'>
                              <div className='kpi-ai-wizard-card-title'>
                                {item.label}
                              </div>
                              <div className='kpi-ai-wizard-card-desc'>
                                {item.desc}
                              </div>
                            </div>
                          </Radio>
                        )
                      } else if (
                        generationType == GenerationType.Multi &&
                        (item.value == kpiTypeEnum.strategicKpi ||
                          item.value == kpiTypeEnum.processKpi)
                      ) {
                        return (
                          <Radio
                            key={item.value}
                            value={item.value}
                            className='kpi-ai-wizard-radio'
                          >
                            <div className='kpi-ai-wizard-card'>
                              <div className='kpi-ai-wizard-card-title'>
                                {item.label}
                              </div>
                              <div className='kpi-ai-wizard-card-desc'>
                                {item.desc}
                              </div>
                            </div>
                          </Radio>
                        )
                      }
                    })}
                  </RadioGroup>
                </FormItem>
              </Col>
            )}
          </Row>
        </Form>
      </div>
      <div className='kpiAi-btn'>
        <Button className='kpiAi-btn-cancel'>{t('common:btn.cancel')}</Button>
        <Button className='kpiAi-btn-next' type='primary' onClick={handleNext}>
          {t('common:btn.next')}
        </Button>
      </div>
    </div>
  )
}

