const formatDate = (date: any): string | null => {
  if (!date) return null
  // dayjs 不能自动解析 DD/MM/YYYY 格式，需要手动转换
  if (typeof date === 'string' && date.includes('/')) {
    const [d, m, y] = date.split('/')
    const parsed = dayjs(`${y}-${m}-${d}`)
    return parsed.isValid() ? parsed.format('DD/MM/YYYY') : null
  }
  const d = dayjs(date)
  return d.isValid() ? d.format('DD/MM/YYYY') : null
}
const formatEmails = (emails: any): string | null => {
  if (!emails) return null
  if (Array.isArray(emails)) {
    return emails.filter(Boolean).join(', ') || null
  }
  const str = String(emails)
  // 处理分号分隔的字符串（KpiInfo 用 '; ' 拼接）
  if (str.includes(';')) {
    return str.split(';').map((e) => e.trim()).filter(Boolean).join(', ') || null
  }
  return str || null
}
